/**
 * Patches the wrangler configs generated by @astrojs/cloudflare to remove
 * fields that cause Cloudflare Pages deployment validation errors.
 */

const fs = require('fs');
const path = require('path');

const ROOT = path.join(__dirname, '..');

/**
 * Apply the standard Pages-compatibility patches to a wrangler config object.
 * Same set of invalid fields appears in both the main and prerender configs.
 */
function patchWranglerConfig(config) {
  // "ASSETS" is a reserved binding name in Pages — remove just the binding
  // declaration but keep assets.directory so Pages knows where static files are.
  // Pages automatically provides the ASSETS binding to the Worker at runtime.
  if (config.assets) {
    delete config.assets.binding;
    if (Object.keys(config.assets).length === 0) {
      delete config.assets;
    }
  }

  // Empty triggers object is invalid — must be absent or { crons: [] }.
  delete config.triggers;

  // Remove all KV namespace entries — real bindings live in the dashboard.
  delete config.kv_namespaces;

  // Pages projects cannot have both "pages_build_output_dir" and "main".
  // This file is the server Worker config so keep "main" and drop the dir.
  delete config.pages_build_output_dir;

  // "rules" and "no_bundle" are Worker-only fields not valid for Pages.
  delete config.rules;
  delete config.no_bundle;

  return config;
}

// --- Patch dist/server/wrangler.json ---
const WRANGLER_JSON = path.join(ROOT, 'dist', 'server', 'wrangler.json');
if (!fs.existsSync(WRANGLER_JSON)) {
  console.log('No dist/server/wrangler.json found — nothing to patch.');
  process.exit(0);
}
const config = patchWranglerConfig(JSON.parse(fs.readFileSync(WRANGLER_JSON, 'utf8')));
fs.writeFileSync(WRANGLER_JSON, JSON.stringify(config, null, 2), 'utf8');
console.log('✓ Patched dist/server/wrangler.json');

// --- Patch dist/server/.prerender/wrangler.json (if it exists) ---
const PRERENDER_JSON = path.join(ROOT, 'dist', 'server', '.prerender', 'wrangler.json');
if (fs.existsSync(PRERENDER_JSON)) {
  const pre = patchWranglerConfig(JSON.parse(fs.readFileSync(PRERENDER_JSON, 'utf8')));
  fs.writeFileSync(PRERENDER_JSON, JSON.stringify(pre, null, 2), 'utf8');
  console.log('✓ Patched dist/server/.prerender/wrangler.json');
}

// --- Fix .wrangler/deploy/config.json ---
// The adapter always emits prerenderWorkerConfigPath pointing to the
// .prerender/wrangler.json file. When output:'server' is set that file is
// never generated, so Cloudflare Pages cannot read it and may fail to set up
// routing, causing all requests to return 404.
// Remove the stale reference when the file does not exist.
const DEPLOY_CONFIG = path.join(ROOT, '.wrangler', 'deploy', 'config.json');
if (fs.existsSync(DEPLOY_CONFIG)) {
  const deploy = JSON.parse(fs.readFileSync(DEPLOY_CONFIG, 'utf8'));
  if (deploy.prerenderWorkerConfigPath) {
    const absPrerender = path.resolve(path.dirname(DEPLOY_CONFIG), deploy.prerenderWorkerConfigPath);
    if (!fs.existsSync(absPrerender)) {
      delete deploy.prerenderWorkerConfigPath;
      fs.writeFileSync(DEPLOY_CONFIG, JSON.stringify(deploy), 'utf8');
      console.log('✓ Removed stale prerenderWorkerConfigPath from .wrangler/deploy/config.json');
    }
  }
}

console.log('✓ All wrangler config patches applied.');

